INSERT INTO `drama` VALUES (1,'北派寻宝笔记','二十一世纪初，东北山村的穷小子项云峰一心想出人头地，机缘下踏入北方一行当，从此踏遍南北山河，闯过无数险地，见识江湖人情百态，结识三教九流各色人物。他一路摸爬滚打，从青涩少年熬成沉稳中年，岁月蹉跎尝尽酸甜冷暖，历经半生风雨，终将一路亲身经历与所见所闻落笔，写成独属于自己的自传','/assets/covers/episode01.png','爽剧,反转,悬疑',1,'2026-06-05 11:19:49','2026-06-07 13:42:47',1,'episode01','北派寻宝笔记'),(2,'天下第一纨绔','皇帝为独女比武招亲，蛮夷欲夺魁。为阻蛮夷，皇帝命高手秦武测试青年。镇北侯之子苏羽表面纨绔，实为隐忍多年报母仇。测试中苏羽一拳重伤秦武，获得资格。比武场上，他再一拳败尽蛮夷，震惊四座，更引出其深藏的另一重惊人身份。','/assets/covers/episode08.png','逆袭,搞笑',1,'2026-06-05 11:19:49','2026-06-07 13:42:47',8,'episode08','天下第一纨绔'),(3,'北往','许成名与赵鹏两位东北汉子，春运买不到票，便骑摩托从云南返乡。一路之上，两人仗义出手，救下轻生女子、帮扶寻亲母子、揭穿骗子骗局，以善意化解种种波折。这段充满温暖与欢笑的旅程，让二人愈发懂得家的意义，也坚定了过完年留在家乡、建设故土的决心，尽显东北人的豪爽仗义与质朴温情。','/assets/covers/episode02.png','剧情，现代',1,'2026-06-06 01:38:32','2026-06-07 13:42:47',2,'episode02','北往'),(4,'荒年全村啃树皮，我有系统满仓肉','程弯弯一觉醒来，竟穿越到古代大河村，成了三十三岁的农妇。四个儿子跪在床前唤娘，儿媳更是身怀六甲，母胎单身三十三年的她，直接升级成了奶奶。她不仅要费心管教四个儿子，还接连遭遇蝗灾、旱灾、雪灾等重重天灾。好在她意外拥有交易商城，凭借商城物资，她定下两个目标：一是带领全家平安度过荒年，二是在古代活出属于自己的精彩人生。本剧改编自番茄小说《荒年全村啃树皮，我有系统满仓肉》，作者朝云紫。','/assets/covers/episode03.png','古代，穿越，奇幻',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',3,'episode03','荒年全村啃树皮，我有系统满仓肉'),(5,'家里家外','1981年，蔡晓艳和陈海清两人闪婚，各自带着孩子组成了新的家庭。蔡晓艳性格泼辣，陈海清却偏爱她。相处中，蔡晓艳温暖了陈海清的女儿陈爽，陈海清也赢得了蔡晓艳儿子邵一帆的信任，一家四口相互支持，日子越过越美好。','/assets/covers/episode04.png','爱情，家庭伦理',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',4,'episode04','家里家外'),(6,'那年冬至','冬至这天，南昭宁与残疾的京烁闪婚。可新婚当晚，京烁对她说的第一句话竟是他一年后打算去死？既然如此，南昭宁决定抓紧享受，随便玩玩，顺便生个漂亮孩子！婚后，南昭宁像一束光照亮了京烁灰暗的世界，成为了他的救赎。在温暖又甜蜜的日常中两人彼此心动，双向奔赴。爱创造奇迹，确认心意的两人携手走向幸福的未来。','/assets/covers/episode05.png','现代，爱情',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',5,'episode05','那年冬至'),(7,'十八岁太奶奶驾到，重整家族荣耀第三部','1955年容遇教授意外去世，一睁眼竟穿到了七十年后一位同名同姓的十八岁少女身上，她儿子已成了七十多岁的董事长，她还有了几个帅气重孙子。这一季容遇经历了纪家三少爷变傻、纪老爷子失恋、灯塔国恶意扣押等事件，但她凭借智慧和能力整顿了一切！','/assets/covers/episode06.png','现代，亲情，穿越',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',6,'episode06','十八岁太奶奶驾到，重整家族荣耀第三部'),(8,'撕夜','前世，江清芷将继承的母亲公司股份赠予校草男友叶俊良，却遭他与父亲江大鸣、继母金美艳、继姐江晴雪合谋杀害。死后她得知母亲也是被这几人害死，而黑道病娇大佬楚辰安为她报仇后殉情，她才明白楚辰安的深情。重生后，虽然楚辰安依旧不相信她的真心，但江清芷果断投向楚辰安，发誓非他不嫁，并开始借助他的权势反击。','/assets/covers/episode07.png','现代，言情',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',7,'episode07','撕夜'),(9,'幸得相遇离婚时','唐颖曾为丈夫当全职太太，怀孕五月却遭其与第三者欺辱赶出。离婚后，她嫁给了极具魅力的江辞云，江辞云助她成长，二人先婚后爱，联手报复前夫与第三者，终获事业爱情双丰收。','/assets/covers/episode09.png','爱情，现代，逆袭',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',9,'episode09','幸得相遇离婚时'),(10,'云渺1：我修仙多年强亿点怎么了','江城顶级权贵周老爷子即将离世，临走前却有挂念之人，不肯咽气，周家人愁眉不展之时，一名绝美女子云渺敲响周家大门，周家人都认为她是周老爷子心上人的后人，然而随着云渺见到周老爷子，周老爷子却奇迹般起身，道出了一个惊人真相。（该剧改编自番茄小说《我，修仙大佬强亿点怎么了》，作者白菜）','/assets/covers/episode10.png','玄幻，民国',1,'2026-06-07 00:36:08','2026-06-07 13:42:47',10,'episode10','云渺1：我修仙多年强亿点怎么了');
/*!40000 ALTER TABLE `drama` ENABLE KEYS */;
UNLOCK TABLES;

