INSERT INTO `highlight` VALUES (1010,3,205,52,57,'COOL','正能量爽点','片段中主角自掏腰包卖房凑齐拖欠的工程款给工人发薪，属于强正向爽点，适合叠加夸赞类高光弹幕，完全不影响主线剧情推进',1,'{\"buttons\": [{\"label\": \"情节反差太爽了！\", \"effect\": \"bubble\", \"optionCode\": \"cool\"}], \"componentType\": \"emotion_button\"}','rag',0.9000,'2026-06-07 13:46:52'),(1011,3,204,124,128,'FAMOUS','名场面','该片段两名男子本想劝说女子，结果劝说全起了反作用属于强反差搞笑情绪点，适合叠加名场面弹幕特效，全程仅做覆盖展示不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"名场面\", \"effect\": \"bubble\", \"optionCode\": \"funny\"}], \"componentType\": \"emotion_button\"}','rag',0.8500,'2026-06-07 13:46:52'),(1012,3,217,83,89,'COOL','爽点打脸','小三和渣男以为正主已死，但是正主直接开门捉奸逮个正着，这个剧情反转非常爽，适合叠加高光弹幕特效增强观众的情绪体验，同时该互动设置不会对后续剧情发展造成任何影响',1,'{\"buttons\": [{\"label\": \"爽\", \"effect\": \"bubble\", \"optionCode\": \"cool\"}], \"componentType\": \"emotion_button\"}','rag',0.9000,'2026-06-07 13:46:52'),(1013,3,218,12,16,'FUNNY','搞笑社死名场面','片段中家政阿姨推门撞见屋内男女亲热、拖把惊得掉落的场景属于强搞笑社死情绪点，适合叠加对应弹幕特效，仅做覆盖展示不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"大型社死现场\", \"effect\": \"bubble\", \"optionCode\": \"funny\"}], \"componentType\": \"emotion_button\"}','rag',0.7800,'2026-06-07 13:46:52'),(1014,3,218,132,140,'FUNNY','反差搞笑','在严肃的环境下，两个黑衣男子一边讲述逝者的遗言内容，一边却表现出激动到仰头大笑的反差情绪，适合叠加搞笑弹幕特效增强反差效果，同时该互动设置不会对后续剧情发展造成任何影响',1,'{\"buttons\": [{\"label\": \"笑出鹅叫\", \"effect\": \"bubble\", \"optionCode\": \"funny\"}], \"componentType\": \"emotion_button\"}','rag',0.9000,'2026-06-07 13:46:52'),(1015,3,218,181,185,'FUNNY','搞笑打脸反差名场面','该片段呈现男子狂笑时被同伴突然扇巴掌，表情瞬间从大笑转为错愕的强反差搞笑打脸名场面，适合叠加搞笑类弹幕特效增强观看体验，不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"笑不活了\", \"effect\": \"bubble\", \"optionCode\": \"funny\"}], \"componentType\": \"emotion_button\"}','rag',0.9000,'2026-06-07 13:46:52'),(1016,3,219,14,20,'COOL','极端嚣张震惊爽点','该片段中惩戒渣男渣女，属于强情绪爽点，适合叠加弹幕特效，全程仅做覆盖展示，不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"这也太无法无天了\", \"effect\": \"bubble\", \"optionCode\": \"cool\"}], \"componentType\": \"emotion_button\"}','rag',0.8500,'2026-06-07 13:46:52'),(1017,3,219,95,110,'COOL','打脸爽点，家属痛斥背叛逝者的恶人，情绪极度解气','该片段属于强情绪的家属怒斥恶人的打脸爽点，适合叠加吐槽类高光弹幕，仅做覆盖展示不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"太解气了骂得好\", \"effect\": \"bubble\", \"optionCode\": \"cool\"}], \"componentType\": \"emotion_button\"}','rag',0.8000,'2026-06-07 13:46:52'),(1018,3,223,78,82,'COOL','怼势利保安爽点','该片段中访客出言嘲讽态度傲慢的势利保安，怼人情节爽快，适合叠加爽感弹幕特效放大情绪，全程仅做覆盖展示不会改动主线剧情',1,'{\"buttons\": [{\"label\": \"太刚了\", \"effect\": \"bubble\", \"optionCode\": \"cool\"}], \"componentType\": \"emotion_button\"}','rag',0.8500,'2026-06-07 13:46:52'),(1019,3,223,142,149,'FUNNY','反差，在紧急追人的时候，摩托车发动不了，观众会觉得好笑，适合设置一个搞笑的高光弹幕','当前片段中角色明确即将启动摩托车追赶逃跑人员，但是迎来巨大反差，摩托车发动不了，导致追赶受阻，这一反差点具有较强的喜剧效果，适合设置一个搞笑的高光弹幕来放大这一情绪，同时该片段也存在明确的动作目标（启动摩托车追人），用户操作可以增强这一动作目标的表现，且增强内容不会改变原片主线剧情走向，符合高光弹幕的设置要求',1,'{\"buttons\": [{\"label\": \"笑出鹅叫\", \"effect\": \"bubble\", \"optionCode\": \"funny\"}], \"componentType\": \"emotion_button\"}','rag',0.9000,'2026-06-07 13:46:52'),(1020,3,204,72,90,'BRANCH','是否停下救人','72s 弹出选择；选择不管女孩离开时播放 b-demo 试错分支，失败后回到 72s 重新选择；选择叫上伙伴救人则继续原片主线。',0,'{\"options\": [{\"label\": \"叫上伙伴去救要跳河的女孩\", \"isCorrect\": true, \"retryTime\": null, \"optionCode\": \"team\", \"resumeTime\": null, \"generationId\": null, \"branchOutcome\": \"MAINLINE\", \"generationMode\": null}, {\"label\": \"不管女孩直接骑摩托离开\", \"failText\": \"\", \"isCorrect\": false, \"retryTime\": 72, \"optionCode\": \"alone\", \"resumeTime\": 72, \"generationId\": 1, \"branchOutcome\": \"TRIAL\", \"generationMode\": \"PREGEN\"}], \"branchMode\": \"trial_and_error\", \"componentType\": \"branch_choice\", \"branchPointTime\": 72}','manual',1.0000,'2026-06-07 23:59:05'),(1021,3,223,150,163,'ACTION','给他打火','150s 自动播放 a-demo 动作互动；动作视频第 1.5 秒暂停显示“点击给他打火”，点击后继续；第 6 秒暂停显示“加速追捕”，点击后 2x 继续追捕，播完回到 163s 继续主线。',1,'{\"label\": \"点击给他打火\", \"optionCode\": \"ignite_fire\", \"resumeTime\": 163, \"autoStart\": true, \"startMode\": \"AUTO\", \"actionPrompt\": {\"label\": \"点击给他打火\", \"optionCode\": \"ignite_fire\", \"showAt\": 1.5, \"pauseUntilClick\": true}, \"speedBoost\": {\"rate\": 2, \"label\": \"加速追捕\", \"showAt\": 6, \"autoHideMs\": 0, \"dismissible\": false, \"pauseUntilClick\": true}, \"userAction\": \"点击给他打火\", \"actionLabel\": \"点击给他打火\", \"generationId\": 2, \"componentType\": \"action_button\", \"generationMode\": \"PREGEN\"}','manual',1.0000,'2026-06-08 00:19:00');
